import java.util.*;

public List<List<String>> displayTable(List<List<String>> orders) {
    TreeSet<String> foodItems = new TreeSet<>();
    TreeMap<Integer, Map<String, Integer>> tableOrders = new TreeMap<>();

    for (List<String> order : orders) {
        foodItems.add(order.get(2));
        int tableNumber = Integer.parseInt(order.get(1));
        tableOrders.putIfAbsent(tableNumber, new HashMap<>());
        tableOrders.get(tableNumber).put(order.get(2), tableOrders.get(tableNumber).getOrDefault(order.get(2), 0) + 1);
    }

    List<List<String>> result = new ArrayList<>();
    List<String> header = new ArrayList<>();
    header.add("Table");
    header.addAll(foodItems);
    result.add(header);

    for (Map.Entry<Integer, Map<String, Integer>> entry : tableOrders.entrySet()) {
        List<String> row = new ArrayList<>();
        row.add(String.valueOf(entry.getKey()));
        for (String food : foodItems) {
            row.add(String.valueOf(entry.getValue().getOrDefault(food, 0)));
        }
        result.add(row);
    }

    return result;
}
```


    1. Initialize a set for unique food items and a map for table orders.
2. Iterate over all orders and add food items to the set and update the table orders map.
3. Prepare a header row with the sorted food items.
4. Iterate over the sorted table orders and create an array for each table with the number of food items ordered.
5. Return the result with the header and table order rows.
